INSERT INTO graphs (id, name, type, created_at, updated_at) VALUES
('d6000000-0000-0000-0000-000000000001', 'Les Grandes Familles de la Mode Streetwear', 'FASHION_MAP', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO nodes (id, graph_id, label, type) VALUES
INSERT INTO node_properties (id, node_id, name, value_type, string_value, date_value, ref_node_id) VALUES
('d6000000-0003-0000-0000-000000000001', 'd6000000-0001-0000-0000-000000000009', 'description', 'STRING', 'Fondé par Shawn Stussy en 1980 en Californie. Premier vrai label streetwear, né de la culture surf et skate. A posé les bases de l''esthétique streetwear mondiale', NULL, NULL),
('d6000000-0003-0000-0000-000000000002', 'd6000000-0001-0000-0000-000000000009', 'fondateur', 'STRING', 'Shawn Stussy', NULL, NULL),
('d6000000-0003-0000-0000-000000000003', 'd6000000-0001-0000-0000-000000000009', 'annee_creation', 'STRING', '1980', NULL, NULL),
('d6000000-0003-0000-0000-000000000004', 'd6000000-0001-0000-0000-000000000010', 'description', 'STRING', 'Fondé par James Jebbia à New York en 1994. Le label streetwear le plus influent au monde. Connu pour ses drops limités et sa collaboration avec Louis Vuitton en 2017. Racheté par VF Corporation pour 2,1 milliards', NULL, NULL),
('d6000000-0003-0000-0000-000000000005', 'd6000000-0001-0000-0000-000000000010', 'fondateur', 'STRING', 'James Jebbia', NULL, NULL),
('d6000000-0003-0000-0000-000000000006', 'd6000000-0001-0000-0000-000000000010', 'annee_creation', 'STRING', '1994', NULL, NULL),
('d6000000-0003-0000-0000-000000000007', 'd6000000-0001-0000-0000-000000000010', 'ville', 'STRING', 'New York', NULL, NULL),
('d6000000-0003-0000-0000-000000000008', 'd6000000-0001-0000-0000-000000000011', 'description', 'STRING', 'Fondé par Nigo en 1993 à Tokyo. A fusionné la culture hip-hop américaine et l''esthétique japonaise. Pionnier du streetwear japonais et des collaborations avec Pharrell Williams', NULL, NULL),
('d6000000-0003-0000-0000-000000000009', 'd6000000-0001-0000-0000-000000000011', 'fondateur', 'STRING', 'Nigo', NULL, NULL),
('d6000000-0003-0000-0000-000000000010', 'd6000000-0001-0000-0000-000000000011', 'annee_creation', 'STRING', '1993', NULL, NULL),
('d6000000-0003-0000-0000-000000000011', 'd6000000-0001-0000-0000-000000000011', 'ville', 'STRING', 'Tokyo, Japon', NULL, NULL),
('d6000000-0003-0000-0000-000000000012', 'd6000000-0001-0000-0000-000000000015', 'description', 'STRING', 'Fondé par Virgil Abloh en 2013. A redéfini la frontière entre luxe et streetwear avec ses guillemets iconiques. Abloh nommé directeur artistique de Louis Vuitton Homme en 2018', NULL, NULL),
('d6000000-0003-0000-0000-000000000013', 'd6000000-0001-0000-0000-000000000015', 'fondateur', 'STRING', 'Virgil Abloh', NULL, NULL),
('d6000000-0003-0000-0000-000000000014', 'd6000000-0001-0000-0000-000000000015', 'annee_creation', 'STRING', '2013', NULL, NULL),
('d6000000-0003-0000-0000-000000000015', 'd6000000-0001-0000-0000-000000000016', 'description', 'STRING', 'Fondé par Jerry Lorenzo en 2013 à Los Angeles. A popularisé le luxe streetwear sombre et oversized. Collaborations avec Nike et Adidas. Habille les plus grandes stars du rap', NULL, NULL),
('d6000000-0003-0000-0000-000000000016', 'd6000000-0001-0000-0000-000000000016', 'fondateur', 'STRING', 'Jerry Lorenzo', NULL, NULL),
('d6000000-0003-0000-0000-000000000017', 'd6000000-0001-0000-0000-000000000016', 'annee_creation', 'STRING', '2013', NULL, NULL),
('d6000000-0003-0000-0000-000000000018', 'd6000000-0001-0000-0000-000000000018', 'description', 'STRING', 'Marque de Kanye West en collaboration avec Adidas depuis 2015. A révolutionné le marché des sneakers avec la Yeezy Boost 350. Collaboration rompue en 2022 suite aux controverses', NULL, NULL),
('d6000000-0003-0000-0000-000000000019', 'd6000000-0001-0000-0000-000000000018', 'fondateur', 'STRING', 'Kanye West', NULL, NULL),
('d6000000-0003-0000-0000-000000000020', 'd6000000-0001-0000-0000-000000000018', 'annee_creation', 'STRING', '2015', NULL, NULL),
('d6000000-0003-0000-0000-000000000021', 'd6000000-0001-0000-0000-000000000020', 'description', 'STRING', 'Sous-marque de Nike créée en 1984 pour Michael Jordan. A révolutionné le marché des sneakers et la culture streetwear. La Air Jordan 1 est devenue le symbole de la culture sneaker mondiale', NULL, NULL),
('d6000000-0003-0000-0000-000000000022', 'd6000000-0001-0000-0000-000000000020', 'annee_creation', 'STRING', '1984', NULL, NULL),
('d6000000-0003-0000-0000-000000000023', 'd6000000-0001-0000-0000-000000000020', 'chiffre_affaires', 'STRING', 'Plus de 5 milliards de dollars par an', NULL, NULL),
('d6000000-0003-0000-0000-000000000024', 'd6000000-0001-0000-0000-000000000028', 'description', 'STRING', 'Designer, artiste et DJ américano-ghanéen (1980-2021). Fondateur d''Off-White et directeur artistique de Louis Vuitton Homme. Figure la plus influente du streetwear de luxe', NULL, NULL),
('d6000000-0003-0000-0000-000000000025', 'd6000000-0001-0000-0000-000000000029', 'description', 'STRING', 'Rappeur et designer américain. A collaboré avec Nike (Air Yeezy), puis Adidas (Yeezy). A popularisé le luxe streetwear dans la culture rap et influencé toute une génération de créateurs', NULL, NULL),
('d6000000-0003-0000-0000-000000000026', 'd6000000-0001-0000-0000-000000000030', 'description', 'STRING', 'Designer japonais fondateur de BAPE. A fusionné la culture hip-hop américaine avec l''esthétique japonaise et posé les bases du streetwear asiatique', NULL, NULL),
('d6000000-0003-0000-0000-000000000027', 'd6000000-0001-0000-0000-000000000027', 'description', 'STRING', 'Fondé par Teddy Santis en 2014 à New York. Marque new-yorkaise qui mêle esthétique méditerranéenne et culture de la rue. Santis nommé directeur créatif de New Balance USA en 2021', NULL, NULL),
('d6000000-0003-0000-0000-000000000028', 'd6000000-0001-0000-0000-000000000027', 'fondateur', 'STRING', 'Teddy Santis', NULL, NULL);
